class OrderProcessingError(Exception):
    """Base class for other exceptions"""
    pass


class InvalidItemError(OrderProcessingError):
    """Raised when an item in an order is invalid"""
    pass


class PricingError(OrderProcessingError):
    """Raised for pricing-related errors"""
    pass


class OrderCancellationError(OrderProcessingError):
    """Raised when an order is cancelled"""
    pass

def calculate_total(items):
    total = 0.0
    for item in items:
        total += item['price']
    return total

def process_order(order_id, items):
    total = calculate_total(items)
    return {
        'order_id': order_id,
        'total': total,
        'status': 'processed'
    }

def main():
    test_items = [
        {'name': 'Item 1', 'price': 10.0},
        {'name': 'Item 2', 'price': 20.0}
    ]
    result = process_order('ORD-001', test_items)
    print(f"Order result: {result}")

    # Example with an item that would have been invalid
    invalid_items = [
        {'name': 'Item 3', 'price': 30.0},
        {'name': 'Item 4', 'price': -5.0} 
    ]
    result = process_order('ORD-002', invalid_items)
    print(f"Order result: {result}")


if __name__ == '__main__':
    main()

